// ── Cookie helpers ────────────────────────────────────────
const COOKIE_KEY = 'stp_session';
const setCookie = (val, days=30) => {
  const exp = new Date(Date.now() + days*864e5).toUTCString();
  document.cookie = `${COOKIE_KEY}=${encodeURIComponent(JSON.stringify(val))};expires=${exp};path=/;SameSite=Lax`;
};
const getCookie = () => {
  try {
    const match = document.cookie.split(';').map(c=>c.trim()).find(c=>c.startsWith(COOKIE_KEY+'='));
    return match ? JSON.parse(decodeURIComponent(match.split('=').slice(1).join('='))) : null;
  } catch { return null; }
};
const clearCookie = () => { document.cookie = `${COOKIE_KEY}=;expires=Thu, 01 Jan 1970 00:00:00 GMT;path=/`; };

// ── Slug routing helpers ──────────────────────────────────
const VALID_SCREENS = ['overview','dealers','monthly','compare','map','outstanding','upload','entry','followups','months','admin','crm','attendance','visits','leads','leaves','reports','tasks','tickets'];
const getScreenFromUrl = () => {
  const hash = window.location.hash.replace('#/','').split('?')[0];
  return VALID_SCREENS.includes(hash) ? hash : 'overview';
};
const pushScreen = (screen, filterPatch=null) => {
  let url = `#/${screen}`;
  if(filterPatch) {
    const params = new URLSearchParams(filterPatch).toString();
    url += `?${params}`;
  }
  window.history.pushState({screen, filterPatch}, '', url);
};

export default function App(){
  const [theme,setTheme]=useState('dark');
  const [users,setUsers]=useState(DEFAULT_USERS);
  const [currentUser,setCurrentUser]=useState(null);
  // Impersonation: when a superadmin uses "Login as" on another user, we store
  // the original superadmin's identity here (and in localStorage) so the top
  // banner can offer one-click return to the original account.
  const [impersonatingFrom,setImpersonatingFrom]=useState(()=>{
    try{ return JSON.parse(localStorage.getItem('stp_impersonating')||'null'); }catch{ return null; }
  });
  // ── Global Login-as dropdown (in the topbar, visible on every screen) ──
  const [loginAsOpen, setLoginAsOpen] = useState(false);
  const [loginAsBusy, setLoginAsBusy] = useState(false);
  const [loginAsErr,  setLoginAsErr]  = useState(null);
  // Anchor position for the fixed dropdown — captured from the button rect
  // so the dropdown can use position:fixed and escape #topbar's overflow:hidden.
  const [loginAsPos,  setLoginAsPos]  = useState({ top: 60, right: 12 });
  const loginAsRef = useRef(null);
  const loginAsBtnRef = useRef(null);
  const [dealers,setDealers]=useState([]);
  const [bootedFromSheets,setBootedFromSheets]=useState(false);
  const [notes,setNotes]=useState([]);
  const [activityLog,setActivityLog]=useState([]);
  const [screen,setScreen]=useState(getScreenFromUrl());
  const [editingId,setEditingId]=useState(null);
  const [showAdd,setShowAdd]=useState(false);
  const [showUM,setShowUM]=useState(false);
  const [selected,setSelected]=useState([]);
  const [bulkAction,setBulkAction]=useState(null);
  const [sidebarOpen,setSidebarOpen]=useState(typeof window!=='undefined'&&window.innerWidth>768);
  const [syncing,setSyncing]=useState(false);
  const [reloadingDB, setReloadingDB] = useState(false);
  const [showApiSettings, setShowApiSettings] = useState(false);
  const [dbLoaded,setDbLoaded]=useState(false);
  const [outstandingData,setOutstandingData]=useState([]);
  const [outFollowups,setOutFollowups]=useState([]);

  // Month config — controlled from admin panel, stored in localStorage
  const [monthConfig,setMonthConfig]=useState(()=>{
    try{
      const saved=JSON.parse(localStorage.getItem('stp_month_config')||'null');
      if(saved&&saved.MO&&saved.MO.length>0) return saved;
    }catch{}
    return { MO:MO_DEFAULT, currentIdx:CURRENT_MONTH_IDX_DEFAULT, label:CURRENT_MONTH_LABEL_DEFAULT, short:CURRENT_MONTH_SHORT_DEFAULT };
  });

  // Expose active MO and currentIdx based on config
  const activeMO          = monthConfig.MO;
  const activeMonthIdx    = monthConfig.currentIdx;
  const activeMonthLabel  = monthConfig.label;
  const [useDB,setUseDB]=useState(false);
  const [dbChecked,setDbChecked]=useState(false);
  const [lastSync,setLastSync]=useState(null);
  const [syncErrs,setSyncErrs]=useState([]);
  const [selectedMonthIdx,setSelectedMonthIdx]=useState(()=>{ try{ const s=JSON.parse(localStorage.getItem('stp_month_config')||'null'); return s?.currentIdx??CURRENT_MONTH_IDX_DEFAULT; }catch{ return CURRENT_MONTH_IDX_DEFAULT; } });
  const [pendingFilters,setPendingFilters]=useState(null);

  // ── Sidebar group expand state (e.g., CRM contains Visits + Leads) ───────
  const [navGroupsOpen, setNavGroupsOpen] = useState(()=>{
    try{ return JSON.parse(localStorage.getItem('stp_nav_groups')||'{"crm":true}'); }
    catch{ return { crm: true }; }
  });
  const toggleNavGroup = (id) => {
    setNavGroupsOpen(prev => {
      const next = { ...prev, [id]: !prev[id] };
      try{ localStorage.setItem('stp_nav_groups', JSON.stringify(next)); }catch{}
      return next;
    });
  };

  // ── Extra theme palette (layers on top of dark/light) ────────────────────
  // Selected via the dropdown beside the Reload DB button. Each palette sets
  // CSS variables directly on document.documentElement; the existing
  // dark/light toggle and Styles.jsx are NOT touched.
  const [paletteId, setPaletteId] = useState(() => loadSavedTheme());
  const [paletteOpen, setPaletteOpen] = useState(false);
  const [palettePos, setPalettePos] = useState({ top: 60, right: 12 });
  const paletteRef    = useRef(null);
  const paletteBtnRef = useRef(null);
  // Apply on mount AND whenever the user picks a different palette
  useEffect(()=>{ applyTheme(paletteId); saveTheme(paletteId); },[paletteId]);
  // Close on outside click
  useEffect(()=>{
    if(!paletteOpen) return;
    const onDoc = (e) => { if(paletteRef.current && !paletteRef.current.contains(e.target)) setPaletteOpen(false); };
    document.addEventListener('mousedown', onDoc);
    return ()=>document.removeEventListener('mousedown', onDoc);
  },[paletteOpen]);

  // ── Refresh user roster from server. Called on boot AND after any
  //     user mutation (create / delete / role change / approver change) so
  //     newly added users show up everywhere — sidebar, login dropdown,
  //     login-as picker, lead assignee picker — without a full reload.
  const refreshUsersFromServer = useCallback(async () => {
    try {
      const fresh = await api.getUsers();
      if(fresh && typeof fresh === 'object'){
        setUsers(fresh);              // overwrite local cache with authoritative server data
        storage.set('users', fresh);  // also persist so we have it offline next boot
      }
    } catch(e){
      console.warn('[refreshUsersFromServer]', e?.message);
    }
  }, []);

  // ── Boot: load storage + restore cookie session ──────────
  useEffect(()=>{
    (async()=>{
      const [u,d,n,l,t]=await Promise.all([
        storage.get('users'),storage.get('dealers'),
        storage.get('notes',[]),storage.get('activityLog',[]),storage.get('theme','dark')
      ]);
      if(u)setUsers(u); if(d)setDealers(d); if(n)setNotes(n); if(l)setActivityLog(l); if(t)setTheme(t);

      // Fire-and-forget: get the live user list from the server. /api/auth/users
      // is public so this works even before login. If it succeeds it overwrites
      // the local cache so the LoginPage dropdown always shows the newest users.
      refreshUsersFromServer();

      // ── Session restore ────────────────────────────────────────────
      // CRITICAL: if we're currently impersonating (stp_impersonating set),
      // we must NOT re-login with the saved cookie — that would overwrite
      // the impersonation JWT with a fresh JWT for the ORIGINAL superadmin.
      // Instead, use the impersonation JWT we already have and call /me to
      // fetch the impersonated user's profile.
      const BASE = import.meta.env?.VITE_API_URL || 'http://localhost:5000/api';
      const impMarker = (()=>{ try{ return JSON.parse(localStorage.getItem('stp_impersonating')||'null'); }catch{ return null; } })();
      const existingToken = localStorage.getItem('stp_jwt');

      if(impMarker && existingToken){
        try {
          const me = await fetch(`${BASE}/auth/me`,{
            headers:{ Authorization:`Bearer ${existingToken}` },
            signal: AbortSignal.timeout(8000),
          }).then(r=>r.ok?r.json():null).catch(()=>null);
          if(me && me.id){
            setCurrentUser(me);
            setUseDB(true);
            setDbChecked(true);
            return; // stop — do NOT fall through to cookie relogin
          } else {
            // Impersonation token is no longer valid — clear marker and
            // fall through to normal cookie-based relogin as the original.
            localStorage.removeItem('stp_impersonating');
            setImpersonatingFrom(null);
          }
        } catch{}
      }

      // Restore session — try server JWT login first, fallback to cookie
      const session = getCookie();
      if(session?.userId && session?.passHash){
        // Try to get fresh JWT from server
        try {
          const res  = await fetch(`${BASE}/auth/login`,{
            method:'POST',
            headers:{'Content-Type':'application/json'},
            body: JSON.stringify({ id:session.userId, pass:session.passHash }),
            signal: AbortSignal.timeout(8000),
          }).then(r=>r.json()).catch(()=>null);

          if(res?.token && res?.user){
            localStorage.setItem('stp_jwt', res.token);
            setCurrentUser(res.user);
            setUseDB(true);
            setDbChecked(true); // trigger loadData with valid token
          } else {
            // Server unavailable — restore from local users
            const allUsers = u || DEFAULT_USERS;
            const user = allUsers[session.userId];
            if(user) setCurrentUser(user);
          }
        } catch(e){
          // Fallback to local
          const allUsers = u || DEFAULT_USERS;
          const user = allUsers[session.userId];
          if(user) setCurrentUser(user);
        }
      }
    })();
  },[]);

  // ── Persist ───────────────────────────────────────────────
  useEffect(()=>{storage.set('users',users);},[users]);
  useEffect(()=>{storage.set('dealers',dealers);},[dealers]);
  useEffect(()=>{storage.set('notes',notes);},[notes]);
  useEffect(()=>{storage.set('activityLog',activityLog);},[activityLog]);
  useEffect(()=>{storage.set('theme',theme);document.documentElement.setAttribute('data-theme',theme);},[theme]);
  useEffect(()=>{
    const onResize=()=>{if(window.innerWidth>768)setSidebarOpen(true);};
    window.addEventListener('resize',onResize);
    return()=>window.removeEventListener('resize',onResize);
  },[]);

  // ── Browser back/forward ──────────────────────────────────
  useEffect(()=>{
    const onPop = (e) => {
      const s = e.state?.screen || getScreenFromUrl();
      if(VALID_SCREENS.includes(s)) setScreen(s);
      if(e.state?.filterPatch) setPendingFilters({...e.state.filterPatch, _ts: Date.now()});
    };
    window.addEventListener('popstate', onPop);
    return () => window.removeEventListener('popstate', onPop);
  },[]);

  // ── Auth ──────────────────────────────────────────────────
  const handleLogin = useCallback((user, token, rawPass) => {
    if(token){ saveToken(token); setUseDB(true); }
    setCurrentUser(user);
    // Store userId + password for auto-relogin on refresh
    setCookie({ userId:user.id, passHash:rawPass||user.pass||'' });
    // push current screen to history
    pushScreen(screen);
  },[screen]);

  const handleLogout = useCallback(() => {
    saveToken(null); setUseDB(false);
    setCurrentUser(null);
    clearCookie();
    localStorage.removeItem('stp_impersonating');
    setImpersonatingFrom(null);
    setScreen('overview');
    window.history.replaceState({screen:'overview'}, '', '#/overview');
  },[]);

  // ── Return to original superadmin (called from impersonation banner) ─────
  // Asks the server for a fresh JWT for the ORIGINAL superadmin, clears the
  // impersonation marker, and reloads so the whole UI re-mounts cleanly.
  const handleReturnToSelf = useCallback(async () => {
    try {
      const res = await api.returnToSelf();
      saveToken(res.token);
      localStorage.removeItem('stp_impersonating');
      setImpersonatingFrom(null);
      setCurrentUser(res.user);
      setTimeout(()=>window.location.reload(), 150);
    } catch(e){
      notify.error('Could not return to your account: ' + e.message + '. Please log in again.');
      handleLogout();
    }
  },[handleLogout]);

  // ── Close global Login-as dropdown on outside click ─────────────────────
  useEffect(()=>{
    if(!loginAsOpen) return;
    const onDoc = (e) => { if(loginAsRef.current && !loginAsRef.current.contains(e.target)) setLoginAsOpen(false); };
    document.addEventListener('mousedown', onDoc);
    return ()=>document.removeEventListener('mousedown', onDoc);
  },[loginAsOpen]);

  // ── Trigger impersonation from anywhere in the app ──────────────────────
  const doLoginAs = useCallback(async (uid, name) => {
    if(loginAsBusy) return;
    setLoginAsErr(null);
    const ok = await confirmDialog({
      title: 'Login as ' + name + '?',
      message: 'You will see exactly what they see. Use the yellow banner at the top to return to your own account at any time.',
      confirmText: 'Login as ' + name,
    });
    if(!ok) return;
    setLoginAsBusy(true);
    try {
      const res = await api.impersonate(uid);
      saveToken(res.token);
      localStorage.setItem('stp_jwt', res.token);
      const impersonatedBy = {
        id:    currentUser.id,
        name:  currentUser.name,
        ini:   currentUser.ini,
        color: currentUser.color,
      };
      localStorage.setItem('stp_impersonating', JSON.stringify(impersonatedBy));
      setImpersonatingFrom(impersonatedBy);
      setCurrentUser(res.user);
      setLoginAsOpen(false);
      setTimeout(()=>window.location.reload(), 200);
    } catch(e){
      // Common cause: stale JWT — user's role was upgraded to superadmin in DB
      // but the JWT they're holding was issued back when they were 'admin', so
      // the server-side superAdminOnly middleware rejects it.
      const msg = (e.message||'').toLowerCase();
      if(msg.includes('superadmin') || msg.includes('403') || msg.includes('not allowed')){
        setLoginAsErr('Your token is out of date. Please Sign out and sign in again, then try Login-as.');
      } else {
        setLoginAsErr('Login-as failed: ' + e.message);
      }
    } finally { setLoginAsBusy(false); }
  },[currentUser, loginAsBusy]);

  const saveMonthConfig = (cfg) => {
    // Stamp with `updatedAt` so loadFromDB can decide which side is fresher.
    // Without this, a stale DB version would silently overwrite recent local
    // edits (e.g., removing a future month) on the next refresh.
    const updated = {...monthConfig,...cfg, updatedAt: Date.now()};
    const moChanged = JSON.stringify(updated.MO) !== JSON.stringify(monthConfig.MO);
    setMonthConfig(updated);
    // Save to localStorage (persists across refresh)
    localStorage.setItem('stp_month_config', JSON.stringify(updated));
    // Also update selectedMonthIdx to new current
    if(cfg.currentIdx!==undefined) setSelectedMonthIdx(cfg.currentIdx);
    // Save to DB if available so all users get same config
    if(getToken()) {
      api.saveMonthConfig(updated).catch(e => {
        console.warn('[saveMonthConfig] DB save failed — config stays in localStorage only:', e.message);
      });
    }
    // If months array changed, re-map existing dealer data to the new MO
    // so dashboards immediately show columns aligned with the new month list.
    if(moChanged && dealers.length > 0){
      setDealers(ds => ds.map(d => {
        if(!d._raw && !d.monthlyData) return d;
        const md = d.monthlyData || {};
        const months       = updated.MO.map(m => Number(md[m]?.achieved) || 0);
        const monthTargets = {};
        updated.MO.forEach((m, i) => { const t = Number(md[m]?.target); if(t > 0) monthTargets[i] = t; });
        return { ...d, months, monthTargets };
      }));
    }
  };

  const toggleTheme=()=>setTheme(t=>t==='dark'?'light':'dark');

  const navigate=useCallback((target, filterPatch=null)=>{
    setScreen(target);
    pushScreen(target, filterPatch);
    if(filterPatch) setPendingFilters({...filterPatch, _ts: Date.now()});
    if(window.innerWidth<=768) setSidebarOpen(false);
  },[]);

  const addLog=useCallback((action,detail)=>{
    setActivityLog(l=>[{id:uid(),action,detail,by:currentUser?.id,at:isoNow()},...l].slice(0,200));
  },[currentUser]);

  // Staff = admin OR superadmin (both see all dealers/notes)
  const isStaff = currentUser?.role==='admin' || currentUser?.role==='superadmin';

  const myDealers=useMemo(()=>{
    if(!currentUser)return[];
    return isStaff?dealers:dealers.filter(d=>d.salesman===currentUser.id);
  },[dealers,currentUser,isStaff]);

  const myNotes=useMemo(()=>{
    if(!currentUser)return[];
    if(isStaff)return notes;
    const myIds=new Set(myDealers.map(d=>d.id));
    return notes.filter(n=>myIds.has(n.dealerId));
  },[notes,myDealers,currentUser,isStaff]);

  const syncSheets=useCallback(async()=>{
    setSyncing(true); const errs=[],live=[];
    for(const s of Object.values(users).filter(u=>u.role==='salesman')){
      // Fetch Sheet 1 (url)
      if(s.url){
        try{
          const csv=await fetchCSV(s.url);
          const rows=parseCSV(csv,s.id);
          if(!rows.length) throw new Error('0 rows');
          live.push(...rows);
        } catch(e){ errs.push(s.name+' Sheet1: '+e.message); }
      }
      // Fetch Sheet 2 (url2) — merge with Sheet 1 dealers by name
      if(s.url2){
        try{
          const csv2=await fetchCSV(s.url2);
          const rows2=parseCSV(csv2,s.id);
          if(!rows2.length) throw new Error('0 rows');
          // Merge: if dealer name already exists from Sheet1, update category breakdown
          // If new dealer, add them
          rows2.forEach(r2=>{
            const existing=live.find(d=>d.salesman===s.id&&d.name.toUpperCase().trim()===r2.name.toUpperCase().trim());
            if(existing){
              // Merge category breakdown from sheet2 into existing dealer
              if(r2.categoryBreakdown){
                if(!existing.categoryBreakdown) existing.categoryBreakdown={};
                Object.entries(r2.categoryBreakdown).forEach(([cat,subs])=>{
                  if(!existing.categoryBreakdown[cat]) existing.categoryBreakdown[cat]={};
                  Object.entries(subs).forEach(([sub,months])=>{
                    if(!existing.categoryBreakdown[cat][sub]) existing.categoryBreakdown[cat][sub]=new Array(11).fill(0);
                    for(let m=0;m<11;m++) existing.categoryBreakdown[cat][sub][m]+=months[m]||0;
                  });
                });
              }
              // Update category/categoryType if sheet2 has more info
              if(r2.category&&!existing.category) existing.category=r2.category;
              if(r2.categoryType&&!existing.categoryType) existing.categoryType=r2.categoryType;
            } else {
              // New dealer only in sheet2 — add them
              live.push(r2);
            }
          });
        } catch(e){ errs.push(s.name+' Sheet2: '+e.message); }
      }
    }
    if(live.length)setDealers(live); setDbLoaded(true);
    // Auto-load outstanding on every sync — from DB if available, else from sheet
    try{
      const token = localStorage.getItem('stp_jwt');
      if(token) {
        const dbOut = await api.getOutstanding().catch(()=>[]);
        if(dbFollowups?.length>0) setOutFollowups(dbFollowups);
      if(dbOut?.length > 0) {
          setOutstandingData(dbOutstandingToApp(dbOut));
        } else {
          // Load from sheet URL and save to DB
          const allU=Object.values(users);
          const src=allU.find(u=>u.role==='admin'&&u.url_outstanding)||allU.find(u=>u.url_outstanding);
          if(src?.url_outstanding){
            const ocsv=await fetchCSV(src.url_outstanding);
            const orows=parseOutstandingCSV(ocsv,src.id);
            setOutstandingData(orows);
          }
        }
      } else {
        // No token — load from sheet directly
        const allU=Object.values(users);
        const src=allU.find(u=>u.role==='admin'&&u.url_outstanding)||allU.find(u=>u.url_outstanding);
        if(src?.url_outstanding){
          const ocsv=await fetchCSV(src.url_outstanding);
          const orows=parseOutstandingCSV(ocsv,src.id);
          setOutstandingData(orows);
        }
      }
    }catch(e){ errs.push('Outstanding: '+e.message); }
    setLastSync(new Date().toLocaleTimeString('en-IN'));
    setSyncErrs(errs);setBootedFromSheets(true);setDbLoaded(true);

    // Save synced sheet data to DB for persistence
    const token = localStorage.getItem('stp_jwt');
    if(token && live.length > 0) {
      try {
        // Normalize monthTargets keys to numbers before sending to DB
        const normalizedLive = live.map(d => ({
          ...d,
          monthTargets: Object.fromEntries(
            Object.entries(d.monthTargets||{}).map(([k,v])=>[Number(k),v])
          )
        }));
        await api.syncToDB(normalizedLive, activeMO);
        console.log('[Sync] Saved', live.length, 'dealers to DB');

        // CRITICAL: Reload from DB so the UI reflects the MERGED state.
        // The sheet parse only has months from the sheet (e.g. May/April/…).
        // The DB might have additional months from manual uploads (e.g. June).
        // Without this reload, the UI would show only the sheet's months and
        // hide manually-uploaded months — which is what made you think June
        // got "removed" by Sync. June is in DB; we just need to fetch it back.
        await loadFromDB(activeMO);
      } catch(e) { console.warn('[Sync] DB save / reload failed:', e.message); }
    }
    setSyncing(false);
    if(currentUser)addLog('sync',`Synced · ${live.length} dealers · ${errs.length} errors`);
  },[users,currentUser,addLog]);


  // Check if backend DB is available - always set dbChecked so app doesn't hang
  useEffect(()=>{
    api.health()
      .then(h=>{ setDbChecked(true); }) // set true regardless - let loadData decide
      .catch(()=>{ setDbChecked(true); }); // even if health fails, proceed
  },[]);

  // Load from DB if JWT exists, else from sheets
  const loadFromDB = async (moOverride) => {
    const token = localStorage.getItem('stp_jwt');
    if(!token) return false;
    try {
      const currentMO = moOverride || activeMO;

      // Load month config, dealers, notes, outstanding all at once.
      // Each call has its own .catch so a single endpoint returning 404 (or
      // a 500) doesn't kill the whole reload — we still set whatever data
      // came back successfully.
      const safe = (p, fallback) => p.then(d => d, e => { console.warn('[loadFromDB partial fail]', e?.message); return fallback; });
      const [dbMonthCfg, dbDealers, dbNotes, dbOut, dbFollowups] = await Promise.all([
        safe(api.getMonthConfig(), null),
        safe(api.getDealers(currentMO), []),
        safe(api.getNotes(), []),
        safe(api.getOutstanding(), []),
        safe(api.getFollowups(), []),
      ]);
      // Normalise to arrays so the rest of the code never NPEs on a 404.
      const _dbDealers   = Array.isArray(dbDealers)   ? dbDealers   : [];
      const _dbNotes     = Array.isArray(dbNotes)     ? dbNotes     : [];
      const _dbOut       = Array.isArray(dbOut)       ? dbOut       : [];
      const _dbFollowups = Array.isArray(dbFollowups) ? dbFollowups : [];

      // Apply month config — TIMESTAMP-based merge so the most recent edit
      // always wins. Whichever of local/DB has the newer `updatedAt` is
      // adopted. This is what prevents a stale DB version from silently
      // re-adding months the user just removed (e.g., deleted future months
      // reappearing after refresh).
      let finalMO = currentMO;
      const localMO = activeMO || [];
      const dbMO    = dbMonthCfg?.MO || [];
      const localTs = monthConfig?.updatedAt || 0;
      const dbTs    = dbMonthCfg?.updatedAt || 0;
      const dbHasConfig    = dbMO.length > 0;
      const localHasConfig = localMO.length > 0;

      if(dbHasConfig && (!localHasConfig || dbTs > localTs)){
        // DB is the freshest source — adopt it
        console.log('[loadFromDB] Adopting DB month-config (dbTs=' + dbTs + ' > localTs=' + localTs + ')');
        setMonthConfig(dbMonthCfg);
        localStorage.setItem('stp_month_config', JSON.stringify(dbMonthCfg));
        if(dbMonthCfg.currentIdx !== undefined) setSelectedMonthIdx(dbMonthCfg.currentIdx);
        finalMO = dbMonthCfg.MO;
      } else if(localHasConfig && (!dbHasConfig || localTs > dbTs)){
        // Local is the freshest source — keep it AND push to DB so other
        // devices catch up next time they load.
        console.log('[loadFromDB] Local month-config is newer (localTs=' + localTs + ' > dbTs=' + dbTs + '). Preserving local + pushing to DB.');
        try { api.saveMonthConfig(monthConfig).catch(() => {}); } catch {}
        finalMO = localMO;
      }
      // Equal timestamps (or both missing) → leave finalMO as currentMO

      // Set dealers — ALWAYS write to state, even if the array is empty.
      // The old `if(appDealers.length > 0)` guard hid genuine empties and
      // made the Reload DB button look broken when the user expected a
      // change. If DB really has no dealers, that's what we should show.
      const appDealers = _dbDealers.map(d => dbDealerToApp(d, finalMO));
      setDealers(appDealers);
      setDbLoaded(true);

      // Set notes (only if endpoint responded)
      setNotes(_dbNotes.map(n=>({
        ...n,
        id:       n._id?.toString()||n.id,
        content:  n.text||n.content||'',    // DB uses 'text', app uses 'content'
        createdBy:n.userId||n.createdBy||'',
        dealerId: n.dealerId||'',
        dueDate:  n.dueDate||null,
        completed:n.completed||false,
        createdAt:n.createdAt||n.updatedAt||new Date().toISOString(),
      })));

      // Set outstanding — if DB has data use it, else try sheet URL
      if(_dbFollowups.length>0) setOutFollowups(_dbFollowups);
      if(_dbOut.length > 0) setOutstandingData(dbOutstandingToApp(_dbOut));

      setLastSync(new Date().toLocaleTimeString('en-IN'));
      setUseDB(true);
      setDbLoaded(true);
      return {
        ok: true,
        count: appDealers.length,
        notes: _dbNotes.length,
        outstanding: _dbOut.length,
        followups: _dbFollowups.length,
      };
    } catch(e) {
      console.warn('DB load failed:', e.message);
      setDbLoaded(true);
      return { ok:false, error: e?.message || 'Reload failed' };
    }
  };

  // Wrapper around loadFromDB that gives the user visible feedback when they
  // tap the "Reload DB" button — spinning icon while running, success toast
  // with the dealer count, error toast if the API failed. Without this the
  // button looked dead because nothing happened in the UI.
  const handleReloadDB = async () => {
    if(reloadingDB) return;
    if(!localStorage.getItem('stp_jwt')){
      notify.error('Sign in to reload from server.');
      return;
    }
    setReloadingDB(true);
    try {
      const res = await loadFromDB(activeMO);
      if(res && res.ok){
        notify.success('Reloaded ' + (res.count || 0) + ' dealers from DB');
      } else {
        notify.error('Reload failed: ' + (res?.error || 'unknown'));
      }
    } catch(e){
      notify.error('Reload failed: ' + (e?.message || e));
    } finally {
      setReloadingDB(false);
    }
  };

  const loadData = async () => {
    const token = localStorage.getItem('stp_jwt');
    if(token) {
      // Only load from DB. DO NOT fall back to syncSheets() — that destroys
      // data the user uploaded manually (e.g. June). If the DB is empty,
      // the user can click "Sync now" in Manage Months explicitly.
      await loadFromDB();
    }
    // If there's no token (offline / not logged in), we just leave the
    // dashboard empty until the user logs in. No silent Sheet sync.
    setDbLoaded(true);
  };

  useEffect(()=>{
    if(currentUser) {
      setTimeout(loadData, 200);
    }
  },[currentUser]);

  // IMPORTANT: Do NOT auto-sync from Sheets here.
  // A previous version had a 3-second timer that auto-called syncSheets() if
  // dealers was still empty after page load. That ran on EVERY page refresh
  // and silently overwrote any data the user had uploaded manually via the
  // Monthly Entry tab — because the sheet doesn't have those months, the
  // sync mapped May into June's slot etc. and destroyed the upload.
  //
  // Sync is now ONLY triggered when the user clicks "Sync now" in
  // Manage Months (or the Sync icon in the top bar). That's the user's
  // explicit intent and won't surprise them on refresh.

  const saveDealer = async (d) => {
    setDealers(ds=>ds.map(x=>x.id===d.id?d:x));
    // DB save handled inside DealerModal
  };
  const updateDealerFields = (id,patch)=>setDealers(ds=>ds.map(x=>x.id===id?{...x,...patch}:x));
  const deleteDealer = async (id) => {
    const ok = await confirmDialog({
      title: 'Delete dealer?',
      message: 'This cannot be undone.',
      confirmText: 'Delete',
      danger: true,
    });
    if(!ok) return;
    const d=dealers.find(x=>x.id===id);
    setDealers(ds=>ds.filter(x=>x.id!==id));
    setNotes(ns=>ns.filter(n=>n.dealerId!==id));
    addLog('delete',`Deleted: ${d?.name}`);
    // Delete from DB
    const token=localStorage.getItem('stp_jwt');
    if(token&&id&&!id.startsWith('local_')){
      try{ await api.deleteDealer(id); }catch(e){ console.warn('DB delete failed:',e.message); }
    }
  };
  const addDealer = (d) => { setDealers(ds=>[...ds,d]); addLog('add',`Added: ${d.name}`); };
  const addNote = async (n) => {
    setNotes(ns=>[...ns,n]); // optimistic
    const token = localStorage.getItem('stp_jwt');
    if(token){
      try{
        const saved = await api.addNote({ dealerId:n.dealerId, userId:n.createdBy,
          type:n.type, text:n.content, dueDate:n.dueDate||null, completed:n.completed||false });
        // Update local note with DB id
        setNotes(ns=>ns.map(x=>x.id===n.id?{...x,id:saved._id||saved.id,_id:saved._id}:x));
      }catch(e){ console.warn('Note save failed:',e.message); }
    }
  };
  const updateNote = async (id,patch) => {
    setNotes(ns=>ns.map(n=>n.id===id?{...n,...patch}:n)); // optimistic
    const token = localStorage.getItem('stp_jwt');
    if(token){
      try{ await api.updateNote(id, { completed:patch.completed, text:patch.content, dueDate:patch.dueDate }); }
      catch(e){ console.warn('Note update failed:',e.message); }
    }
  };
  const deleteNote = async (id) => {
    setNotes(ns=>ns.filter(n=>n.id!==id)); // optimistic
    const token = localStorage.getItem('stp_jwt');
    if(token){
      try{ await api.deleteNote(id); }
      catch(e){ console.warn('Note delete failed:',e.message); }
    }
  };

  const applyBulk=action=>{
    if(action.type==='delete'){setDealers(ds=>ds.filter(d=>!selected.includes(d.id)));setNotes(ns=>ns.filter(n=>!selected.includes(n.dealerId)));addLog('bulk',`Deleted ${selected.length}`);}
    else if(action.type==='status'){setDealers(ds=>ds.map(d=>selected.includes(d.id)?{...d,status:action.value}:d));addLog('bulk',`Status → ${action.value} for ${selected.length}`);}
    else if(action.type==='salesman'){setDealers(ds=>ds.map(d=>selected.includes(d.id)?{...d,salesman:action.value}:d));addLog('bulk',`Reassigned ${selected.length}`);}
    setSelected([]);setBulkAction(null);
  };

  // ── Derived values (MUST be before any early return) ────────
  // Topbar snapshot: only count dealers with data for selected month
  const ttSnap=myDealers
    .filter(x=>x.monthsWithData?.has(selectedMonthIdx)||!x.monthsWithData||x.monthsWithData.size===0)
    .reduce((s,x)=>s+((x.monthTargets?.[selectedMonthIdx] ?? x.monthTargets?.[String(selectedMonthIdx)])||0),0);
  const taSnap=myDealers
    .reduce((s,x)=>s+(x.months?.[selectedMonthIdx]||0),0);
  const sbP=pct(ttSnap,taSnap);
  const overdueCount=myNotes.filter(n=>n.type==='followup'&&!n.completed&&n.dueDate&&new Date(n.dueDate)<new Date()).length;
  const editing=editingId?dealers.find(x=>x.id===editingId):null;

  if(!currentUser){
    return(<><Styles theme={theme}/><LoginPage users={users} onLogin={handleLogin} theme={theme} toggleTheme={toggleTheme}/><NotificationCenter/></>);
  }

  // All status counts for territory bar (plain derivation, no hook)
  const allStatuses = (() => { const map={}; myDealers.forEach(d=>{ const s=(d.status||'OTHER').trim()||'OTHER'; map[s]=(map[s]||0)+1; }); return map; })();
  const activeCount = (allStatuses['ACTIVE']||0)+(allStatuses['ACHIVERS']||0)+(allStatuses['ACHIEVERS']||0)+(allStatuses['KEY ACCOUNT']||0);
  const inactiveCount = (allStatuses['INACTIVE']||0)+(allStatuses['REACTIVE']||0);
  const deadCount = allStatuses['DEAD']||0;

  const navItems=[
    {id:'overview',label:'Overview',icon:LayoutDashboard},
    {id:'dealers',label:'All Dealers',icon:Users},
    {id:'monthly',label:'Monthly Trend',icon:TrendingUp},
    {id:'compare',label:'Compare',icon:GitCompare},
    {id:'map',label:'Map View',icon:Map},
    {id:'outstanding',label:'Outstanding',icon:AlertTriangle},
    {id:'upload',label:'Upload Data',icon:Upload,adminOnly:true},
    {id:'salesCat',   label:'Sales by Category',  icon:BarChart3},
    {id:'entry',label:'Monthly Entry',icon:Edit3,adminOnly:true},
    {id:'months',label:'Manage Months',icon:Calendar,adminOnly:true},
    {id:'followups',label:'Follow-ups',icon:Bell,badge:overdueCount},
    {id:'attendance',label:'Attendance',icon:Camera},
    // CRM is a collapsible group with Visits + Leads + Tasks as children.
    { group:'crm', label:'CRM', icon:Briefcase, children:[
        {id:'visits', label:'Visits', icon:ClipboardList},
        {id:'leads',  label:'Leads',  icon:UserCheck},
        {id:'tasks',  label:'Tasks',  icon:CheckSquare},
    ]},
    {id:'leaves',  label:'Leaves',  icon:Plane},
    {id:'tickets', label:'Support', icon:LifeBuoy},
    ...(isStaff?[{id:'reports', label:'Reports', icon:FileSpreadsheet}]:[]),
    ...(isStaff?[{id:'admin',label:'Admin Panel',icon:Settings}]:[]),
  ];

  return(
    <MonthContext.Provider value={{selectedMonthIdx,setSelectedMonthIdx,MO:activeMO,currentMonthIdx:activeMonthIdx,currentMonthLabel:activeMonthLabel}}>
      <>
        <Styles theme={theme}/>
        <div id="app" style={{display:'flex',flexDirection:'column',height:'100vh'}}>

          {/* ── Impersonation banner ── only when a superadmin is logged-in
              as another user. Lets them return to their own account with
              one click (no password re-entry). */}
          {impersonatingFrom && (
            <div style={{
              display:'flex',alignItems:'center',gap:10,
              padding:'8px 14px',
              background:'linear-gradient(90deg, rgba(251,191,36,0.18), rgba(251,191,36,0.08))',
              borderBottom:'1px solid rgba(251,191,36,0.40)',
              color:'#fbbf24',fontSize:12,fontWeight:600,
              flexShrink:0,
            }}>
              <span style={{
                background:'#fbbf24',color:'#1f1300',
                padding:'2px 7px',borderRadius:4,fontSize:10,fontWeight:800,letterSpacing:'.06em',
              }}>VIEWING AS</span>
              <Avatar user={currentUser} size={20}/>
              <span style={{color:'#fde68a'}}>{currentUser?.name}</span>
              <span style={{color:'rgba(251,191,36,0.55)'}}>·</span>
              <span style={{color:'rgba(251,191,36,0.85)',fontWeight:500}}>
                You see exactly what they see
              </span>
              <div style={{flex:1}}/>
              <button onClick={handleReturnToSelf}
                style={{
                  display:'flex',alignItems:'center',gap:6,
                  padding:'5px 12px',borderRadius:5,
                  background:'#fbbf24',color:'#1f1300',
                  border:'none',cursor:'pointer',
                  fontSize:11,fontWeight:700,letterSpacing:'.03em',
                  whiteSpace:'nowrap',
                }}
                title={'Return to ' + (impersonatingFrom?.name || 'your account')}>
                <LogOut size={12}/> Return to {impersonatingFrom?.name || 'my account'}
              </button>
            </div>
          )}

          {/* ── Topbar ── */}
          <div id="topbar">
            {/* ── Hamburger ── always visible */}
            <button onClick={()=>setSidebarOpen(s=>!s)} className="btn"
              style={{padding:'6px 8px',border:'none',background:'none',color:'var(--t3)',flexShrink:0}}>
              <Menu size={18}/>
            </button>

            {/* ── Brand — hide on very small ── */}
            <div className="topbar-brand" style={{fontFamily:'"JetBrains Mono",monospace',fontSize:11,color:'var(--acc)',letterSpacing:3,fontWeight:500,flexShrink:0,whiteSpace:'nowrap'}}>
              ▸ STP
            </div>

            {/* ── Territory bar — hidden on mobile via CSS ── */}
            <div className="territory-bar" style={{display:'flex',alignItems:'center',gap:10,padding:'4px 12px',background:'var(--bg2)',borderRadius:8,border:'1px solid var(--b2)',fontSize:11,flexShrink:0}}>
              <span style={{color:'var(--t3)',fontSize:10,textTransform:'uppercase',letterSpacing:'.08em'}}>{activeMO[selectedMonthIdx].slice(0,3)}</span>
              <span style={{color:'#34d399',fontWeight:700}}>{taSnap}<span style={{color:'var(--t3)',fontWeight:400,marginLeft:2}}>/{ttSnap}</span></span>
              <span style={{color:pclr(sbP),fontWeight:700}}>{spct(ttSnap,taSnap)}</span>
              <span style={{width:1,height:12,background:'var(--b2)',flexShrink:0}}/>
              <span style={{color:'#34d399',fontSize:11}} title="Active">●{activeCount}</span>
              <span style={{color:'#fbbf24',fontSize:11}} title="Inactive">◑{inactiveCount}</span>
              <span style={{color:'#f87171',fontSize:11}} title="Dead">○{deadCount}</span>
            </div>

            <div className="spacer"/>

            {/* ── Sync status dot — always visible ── */}
            {lastSync&&(
              <div style={{display:'flex',alignItems:'center',gap:4,flexShrink:0}}>
                <span style={{width:7,height:7,borderRadius:'50%',background:syncErrs.length?'var(--red)':'var(--grn)',flexShrink:0}}/>
                <span className="hide-sm" style={{fontSize:10,color:'var(--t3)',whiteSpace:'nowrap'}}>{lastSync}</span>
              </div>
            )}

            {/* ── Backend URL settings (gear) — important for mobile/APK ── */}
            <button onClick={() => setShowApiSettings(true)} className="btn"
              title="Set the backend server URL (needed when using the APK or remote server)"
              style={{fontSize:11,display:'flex',alignItems:'center',gap:4,padding:'6px 8px',flexShrink:0,color:'var(--t3)'}}>
              <Settings size={13}/>
            </button>

            {/* ── Login as ▼ — superadmin only, visible on every screen ── */}
            {currentUser?.role==='superadmin' && (
              <div ref={loginAsRef} style={{flexShrink:0}}>
                <button ref={loginAsBtnRef} className="btn"
                  onClick={()=>{
                    // Compute absolute position (viewport coordinates) for the
                    // fixed-position dropdown so it doesn't get clipped by
                    // #topbar's overflow:hidden.
                    const r = loginAsBtnRef.current?.getBoundingClientRect();
                    if(r){
                      setLoginAsPos({
                        top: r.bottom + 6,
                        right: Math.max(8, window.innerWidth - r.right),
                      });
                    }
                    setLoginAsOpen(o=>!o);
                  }}
                  title="Sign in as another user without their password"
                  style={{
                    fontSize:11, display:'flex', alignItems:'center', gap:4, padding:'6px 8px',
                    background:'rgba(251,191,36,0.10)',
                    border:'1px solid rgba(251,191,36,0.35)',
                    color:'#fbbf24', fontWeight:700,
                  }}>
                  <LogIn size={13}/>
                  <span className="hide-sm">Login as</span>
                  <ChevronDown size={11} style={{transform:loginAsOpen?'rotate(180deg)':'rotate(0)', transition:'transform .15s'}}/>
                </button>
                {loginAsOpen && (
                  <>
                    {/* Mobile backdrop — full-screen dim + tap-to-close.
                        On desktop the small popover is enough; this gives
                        phones a clear way to dismiss. */}
                    <div
                      onClick={()=>setLoginAsOpen(false)}
                      style={{
                        position:'fixed', inset:0, zIndex:9998,
                        background:'rgba(0,0,0,0.55)',
                      }}/>
                    <div style={(()=>{
                      const isMobile = typeof window !== 'undefined' && window.innerWidth <= 640;
                      return isMobile ? {
                        // Full-width bottom-sheet style on phones
                        position:'fixed', left:8, right:8, bottom:8, zIndex:9999,
                        background:'var(--bg2)', border:'1px solid var(--b2)',
                        borderRadius:12, maxHeight:'70vh', overflowY:'auto',
                        boxShadow:'0 -10px 30px rgba(0,0,0,0.55)', padding:8,
                      } : {
                        position:'fixed', top:loginAsPos.top, right:loginAsPos.right, zIndex:9999,
                        background:'var(--bg2)', border:'1px solid var(--b2)',
                        borderRadius:8, minWidth:260, maxHeight:380, overflowY:'auto',
                        boxShadow:'0 10px 30px rgba(0,0,0,0.45)', padding:6,
                      };
                    })()}>
                    <div style={{
                      display:'flex', alignItems:'center', justifyContent:'space-between',
                      padding:'8px 10px 6px',
                    }}>
                      <div style={{fontSize:10, color:'var(--t3)', letterSpacing:'.12em', textTransform:'uppercase'}}>
                        Pick a user
                      </div>
                      <button onClick={()=>setLoginAsOpen(false)}
                        style={{background:'none', border:'none', color:'var(--t3)', cursor:'pointer', padding:4}}>
                        ✕
                      </button>
                    </div>
                    {loginAsErr && (
                      <div style={{
                        fontSize:11, color:'#fca5a5', padding:'6px 10px',
                        background:'rgba(248,113,113,0.10)', border:'1px solid #7f1d1d',
                        borderRadius:6, margin:'4px 6px',
                      }}>{loginAsErr}</div>
                    )}
                    {Object.values(users||{})
                      .filter(u => u.id !== currentUser?.id)
                      .sort((a,b)=>{
                        const order = { salesman:0, admin:1, superadmin:2 };
                        const r = (order[a.role]??9) - (order[b.role]??9);
                        if(r !== 0) return r;
                        return (a.name||'').localeCompare(b.name||'');
                      })
                      .map(u => {
                        const isSA = u.role === 'superadmin';
                        const isAd = u.role === 'admin';
                        const RoleIcon = isSA ? ShieldCheck : isAd ? Shield : null;
                        const roleColor = isSA ? '#fbbf24' : isAd ? '#a5b4fc' : '#86efac';
                        return (
                          <div key={u.id}
                            onClick={()=>!loginAsBusy && doLoginAs(u.id, u.name)}
                            style={{
                              display:'flex', alignItems:'center', gap:10,
                              padding:'12px 12px', borderRadius:8,
                              cursor: loginAsBusy?'wait':'pointer',
                              opacity: loginAsBusy?0.6:1,
                              background:'var(--bg1)', marginBottom:6,
                            }}>
                            <Avatar user={u} size={32}/>
                            <div style={{flex:1, minWidth:0}}>
                              <div style={{fontSize:13, fontWeight:600, display:'flex', alignItems:'center', gap:6}}>
                                <span style={{whiteSpace:'nowrap', overflow:'hidden', textOverflow:'ellipsis'}}>{u.name}</span>
                                {RoleIcon && <RoleIcon size={11} style={{color:roleColor, flexShrink:0}}/>}
                              </div>
                              <div style={{fontSize:10, color:'var(--t3)'}}>{u.id} · <span style={{color:roleColor}}>{u.role}</span></div>
                            </div>
                            <div style={{
                              display:'inline-flex', alignItems:'center', gap:4,
                              fontSize:10, fontWeight:700, padding:'5px 9px', borderRadius:6,
                              background:'rgba(251,191,36,0.15)', color:'#fbbf24',
                              border:'1px solid rgba(251,191,36,0.35)',
                            }}>
                              <LogIn size={11}/> Login
                            </div>
                          </div>
                        );
                      })}
                    {Object.values(users||{}).filter(u=>u.id!==currentUser?.id).length === 0 && (
                      <div style={{fontSize:11, color:'var(--t3)', padding:'10px'}}>No other users yet.</div>
                    )}
                    </div>
                  </>
                )}
              </div>
            )}

            {/* ── Theme palette ▼ — visible on every screen ───────────── */}
            <div ref={paletteRef} style={{flexShrink:0}}>
              <button ref={paletteBtnRef} className="btn"
                onClick={()=>{
                  // Anchor the dropdown via viewport coords so #topbar's
                  // overflow:hidden doesn't clip it.
                  const r = paletteBtnRef.current?.getBoundingClientRect();
                  if(r){
                    setPalettePos({
                      top: r.bottom + 6,
                      right: Math.max(8, window.innerWidth - r.right),
                    });
                  }
                  setPaletteOpen(o=>!o);
                }}
                title="Pick a colour palette"
                style={{
                  fontSize:11, display:'flex', alignItems:'center', gap:4, padding:'6px 8px',
                  color:'var(--t2)',
                }}>
                <Palette size={13}/>
                <span className="hide-sm">Theme</span>
                <ChevronDown size={11} style={{transform:paletteOpen?'rotate(180deg)':'rotate(0)', transition:'transform .15s'}}/>
              </button>
              {paletteOpen && (
                <div style={{
                  position:'fixed', top:palettePos.top, right:palettePos.right, zIndex:9999,
                  background:'var(--bg2)', border:'1px solid var(--b2)',
                  borderRadius:8, minWidth:240, maxHeight:420, overflowY:'auto',
                  boxShadow:'0 10px 30px rgba(0,0,0,0.45)', padding:6,
                }}>
                  <div style={{fontSize:9, color:'var(--t3)', letterSpacing:'.12em', textTransform:'uppercase', padding:'6px 10px 4px'}}>
                    Theme — {THEMES.length} palettes
                  </div>
                  {THEMES.map(t => {
                    const selected = t.id === paletteId;
                    return (
                      <div key={t.id}
                        onClick={()=>{ setPaletteId(t.id); setPaletteOpen(false); }}
                        style={{
                          display:'flex', alignItems:'center', gap:8,
                          padding:'7px 10px', borderRadius:6, cursor:'pointer',
                          background: selected ? 'var(--bg1)' : 'transparent',
                          border: selected ? '1px solid var(--acc)' : '1px solid transparent',
                        }}
                        onMouseEnter={e=>{ if(!selected) e.currentTarget.style.background='var(--bg1)'; }}
                        onMouseLeave={e=>{ if(!selected) e.currentTarget.style.background='transparent'; }}>
                        {/* Swatch */}
                        <div style={{display:'flex', gap:2, flexShrink:0}}>
                          {(t.swatch||[]).slice(0,3).map((c,i)=>(
                            <div key={i} style={{
                              width:10, height:18, borderRadius: i===0?'3px 0 0 3px':(i===(t.swatch.length-1)?'0 3px 3px 0':0),
                              background: c, border: '1px solid rgba(255,255,255,0.06)',
                            }}/>
                          ))}
                        </div>
                        <div style={{flex:1, minWidth:0, fontSize:12, fontWeight: selected?700:500, color:'var(--t1)'}}>
                          {t.name}
                        </div>
                        {selected && <Check size={12} style={{color:'var(--acc)', flexShrink:0}}/>}
                      </div>
                    );
                  })}
                </div>
              )}
            </div>

            {/* ── Reload from DB button — safe refresh, doesn't touch Sheets ── */}
            <button onClick={handleReloadDB} disabled={syncing || reloadingDB} className="btn"
              title="Reload all dealer data from MongoDB. Safe — never touches Google Sheets."
              style={{fontSize:11,display:'flex',alignItems:'center',gap:4,padding:'6px 8px',flexShrink:0,color:'#86efac'}}>
              <RefreshCw size={13} className={reloadingDB?'spin':''}/>
              <span className="hide-sm">{reloadingDB ? 'Reloading…' : 'Reload DB'}</span>
            </button>

            {/* ── Sync from Sheets button — icon only on mobile ── */}
            <button onClick={syncSheets} disabled={syncing} className="btn"
              title="Pull latest from Google Sheets. Months not in the sheet are preserved."
              style={{fontSize:11,display:'flex',alignItems:'center',gap:4,padding:'6px 8px',flexShrink:0}}>
              <RefreshCw size={13} className={syncing?'spin':''}/>
              <span className="hide-sm">{syncing?'Syncing':'Sync Sheets'}</span>
            </button>
            {useDB&&<span style={{fontSize:10,background:'rgba(52,211,153,0.15)',color:'#34d399',padding:'2px 7px',borderRadius:4,fontWeight:600,flexShrink:0}}>🗄 DB</span>}

            {/* ── Divider ── */}
            <div className="hide-sm" style={{width:1,height:18,background:'var(--b1)',flexShrink:0}}/>

            {/* ── Theme toggle ── */}
            <div className="theme-toggle" onClick={toggleTheme} title="Toggle theme" style={{flexShrink:0}}/>

            {/* ── Divider ── */}
            <div className="hide-sm" style={{width:1,height:18,background:'var(--b1)',flexShrink:0}}/>

            {/* ── Avatar + name ── */}
            <Avatar user={currentUser} size={26}/>
            <div className="hide-sm" style={{display:'flex',flexDirection:'column'}}>
              <div style={{fontSize:12,fontWeight:600,color:'var(--t1)',lineHeight:1.1,whiteSpace:'nowrap'}}>{currentUser.name}</div>
              <div style={{fontSize:10,color:'var(--t3)'}}>{currentUser.role==='superadmin'?'Superadmin':currentUser.role==='admin'?'Admin':'Sales'}</div>
            </div>

            {/* ── Sign out — always visible, icon + text on desktop ── */}
            <button onClick={handleLogout} className="btn"
              style={{padding:'6px 8px',fontSize:11,color:'var(--t3)',display:'flex',alignItems:'center',gap:4,flexShrink:0}}>
              <LogOut size={13}/>
              <span className="hide-sm">Sign out</span>
            </button>
          </div>

          <MonthSelectorBar
            selectedMonthIdx={selectedMonthIdx}
            setSelectedMonthIdx={setSelectedMonthIdx}
            onRefreshMonth={async (m) => {
              // Per-month refresh: fetch all dealers from DB and surgically
              // update ONLY this month's slot in each dealer in local state.
              // Does NOT touch Google Sheets. Does NOT replace other months.
              const token = localStorage.getItem('stp_jwt');
              if(!token) return;
              try {
                const dbDealers = await api.getDealers(activeMO);
                const i = activeMO.indexOf(m);
                if(i < 0) return;
                setDealers(ds => ds.map(existing => {
                  const fresh = dbDealers.find(x =>
                    (x._id?.toString?.() === existing.id) ||
                    (x.id === existing.id) ||
                    (x.name === existing.name && x.salesman === existing.salesman)
                  );
                  if(!fresh) return existing;
                  const freshMd = fresh.monthlyData || {};
                  const freshEntry = freshMd[m] || null;
                  const newMonths = [...(existing.months || [])];
                  while(newMonths.length < activeMO.length) newMonths.push(0);
                  newMonths[i] = Number(freshEntry?.achieved) || 0;
                  const newMonthTargets = { ...(existing.monthTargets || {}) };
                  if(Number(freshEntry?.target) > 0) newMonthTargets[i] = Number(freshEntry.target);
                  else delete newMonthTargets[i];
                  const newMonthlyData = { ...(existing.monthlyData || {}) };
                  if(freshEntry) newMonthlyData[m] = freshEntry;
                  else delete newMonthlyData[m];
                  return { ...existing, months:newMonths, monthTargets:newMonthTargets, monthlyData:newMonthlyData };
                }));
                console.log('[Refresh ' + m + '] updated ' + dbDealers.length + ' dealer rows from DB');
              } catch(e){
                console.warn('[Refresh ' + m + '] failed:', e.message);
              }
            }}
          />

          <div id="body">
            {sidebarOpen&&window.innerWidth<=768&&<div id="sb-overlay" className="open" onClick={()=>setSidebarOpen(false)}/>}
            <div id="sidebar" className={sidebarOpen?'open':'closed'}>
              <div className="nav-sec">Navigation</div>
              {navItems.filter(n=>!n.adminOnly||isStaff).map((n, idx)=>{
                // Render a collapsible group (parent header + children)
                if(n.group){
                  const GIcon = n.icon;
                  const isOpen = !!navGroupsOpen[n.group];
                  const anyChildActive = (n.children||[]).some(c => c.id === screen);
                  return (
                    <React.Fragment key={'g-'+n.group}>
                      <div className={`nav-item ${anyChildActive?'active':''}`}
                        onClick={()=>toggleNavGroup(n.group)}>
                        <GIcon size={14}/>
                        <span style={{flex:1}}>{n.label}</span>
                        <ChevronDown size={12}
                          style={{transform: isOpen?'rotate(180deg)':'rotate(0)', transition:'transform .15s', color:'var(--t3)'}}/>
                      </div>
                      {isOpen && (n.children||[]).map(c => {
                        const CIcon = c.icon;
                        return (
                          <div key={c.id}
                            className={`nav-item ${screen===c.id?'active':''}`}
                            style={{paddingLeft:32}}
                            onClick={()=>navigate(c.id)}>
                            <CIcon size={13}/><span style={{flex:1}}>{c.label}</span>
                          </div>
                        );
                      })}
                    </React.Fragment>
                  );
                }
                // Flat nav item (default)
                const Icon = n.icon;
                return (
                  <div key={n.id} className={`nav-item ${screen===n.id?'active':''}`} onClick={()=>navigate(n.id)}>
                    <Icon size={14}/><span style={{flex:1}}>{n.label}</span>
                    {n.badge>0&&<span style={{background:'var(--red)',color:'#fff',borderRadius:10,padding:'1px 7px',fontSize:10,fontWeight:700}}>{n.badge}</span>}
                  </div>
                );
              })}
              <div style={{flex:1}}/>
              {/* Sidebar snapshot */}
              <div style={{padding:'14px 16px',borderTop:'1px solid var(--b1)'}}>
                <div style={{fontSize:9,color:'var(--t3)',textTransform:'uppercase',letterSpacing:'.12em',marginBottom:4}}>{activeMO[selectedMonthIdx]} Snapshot</div>
                {selectedMonthIdx!==activeMonthIdx&&<div style={{fontSize:9,color:'#fbbf24',marginBottom:4}}>HISTORICAL</div>}
                <div style={{fontSize:22,fontWeight:700,color:pclr(sbP)}}>{taSnap} units</div>
                <div style={{fontSize:10,color:'var(--t3)',marginBottom:6}}>{taSnap} / {ttSnap} · {spct(ttSnap,taSnap)}</div>
                <div className="prog-bar"><div className="prog-fill" style={{width:`${Math.min(sbP||0,100)}%`,background:pclr(sbP)}}/></div>
                <div style={{marginTop:10,display:'flex',flexDirection:'column',gap:3}}>
                  {Object.entries(allStatuses).sort((a,b)=>{
                    // Custom priority — top-tier customers first, then activity tiers, then dead.
                    const order = {
                      'STAR':0, 'KEY ACCOUNT':1,
                      'ACHIEVER':2, 'ACHIEVERS':2, 'ACHIVERS':2,
                      'ACTIVE':3,
                      'REACTIVE':4, 'INACTIVE':5, 'DEAD':6,
                    };
                    const sa = a[0].toUpperCase(), sb = b[0].toUpperCase();
                    const ra = order[sa] ?? 99, rb = order[sb] ?? 99;
                    if(ra !== rb) return ra - rb;
                    return b[1] - a[1]; // tie-break by larger count
                  }).map(([s,c])=>{
                    const statusColors={'STAR':'#fbbf24','KEY ACCOUNT':'#a78bfa','ACTIVE':'#34d399','ACHIVERS':'#34d399','ACHIEVERS':'#34d399','ACHIEVER':'#34d399','INACTIVE':'#fbbf24','REACTIVE':'#fb923c','DEAD':'#f87171'};
                    const cl=statusColors[s.toUpperCase()]||'#55546a';
                    return(<div key={s} style={{display:'flex',justifyContent:'space-between',fontSize:10}}>
                      <span style={{color:cl,overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap',maxWidth:110}}>{s}</span>
                      <span style={{color:'var(--t2)',fontWeight:600}}>{c}</span>
                    </div>);
                  })}
                </div>
              </div>
              {/* ── Sidebar bottom: user identity + Sign out ─────────── */}
              <div style={{
                padding:'10px 12px', borderTop:'1px solid var(--b1)',
                display:'flex', alignItems:'center', gap:10,
              }}>
                <Avatar user={currentUser} size={30}/>
                <div style={{flex:1, minWidth:0}}>
                  <div style={{fontSize:12, fontWeight:600, color:'var(--t1)', lineHeight:1.1, whiteSpace:'nowrap', overflow:'hidden', textOverflow:'ellipsis'}}>{currentUser.name}</div>
                  <div style={{fontSize:10, color:'var(--t3)'}}>{currentUser.role==='superadmin'?'Superadmin':currentUser.role==='admin'?'Admin':'Sales'}</div>
                </div>
                <button onClick={handleLogout} className="btn"
                  title="Sign out"
                  style={{
                    padding:'6px 10px', fontSize:11, color:'#fca5a5',
                    border:'1px solid rgba(248,113,113,0.35)',
                    background:'rgba(248,113,113,0.08)',
                    display:'inline-flex', alignItems:'center', gap:4,
                  }}>
                  <LogOut size={12}/> Sign out
                </button>
              </div>
            </div>

            <div id="main">
              {(!dbLoaded || (dealers.length===0 && syncing))?<SkeletonLoader screen={screen}/>:(
                <>
                  {screen==='overview'  &&<Overview dealers={myDealers} currentUser={currentUser} users={users} notes={myNotes} onOpenDealer={setEditingId} onNavigate={navigate}/>}
                  {screen==='dealers'   &&<DealersList dealers={myDealers} currentUser={currentUser} users={users} onEdit={setEditingId} onDelete={deleteDealer} onAdd={()=>setShowAdd(true)} selected={selected} setSelected={setSelected} onBulkAction={setBulkAction} notes={myNotes} pendingFilters={pendingFilters} clearPending={()=>setPendingFilters(null)} onUpdateDealer={updateDealerFields}/>}
                  {screen==='monthly'   &&<MonthlyTrend dealers={myDealers} currentUser={currentUser} users={users} onOpenDealer={setEditingId}/>}
                  {screen==='compare'   &&<Compare dealers={myDealers} onOpenDealer={setEditingId}/>}
                  {screen==='map'       &&<IndiaMap dealers={myDealers} users={users} onOpenDealer={setEditingId}/>}
                  {screen==='outstanding'&&<Outstanding dealers={myDealers} users={users} onOpenDealer={setEditingId} currentUser={currentUser} outstandingData={outstandingData} setOutstandingData={setOutstandingData}/>}
                  {screen==='upload'&&<UploadMonth users={users} currentUser={currentUser} onSuccess={()=>loadFromDB(activeMO)}/>}
                  {screen==='salesUpload' && isStaff && <SalesUpload currentUser={currentUser} onUploaded={()=>{}}/>}
                  {screen==='salesCat'    && <SalesByCategory currentUser={currentUser} users={users} dealers={dealers} onOpenDealer={setEditingId}/>}
                  {screen==='entry'&&<MonthlyEntry dealers={myDealers} users={users} currentUser={currentUser} onUpdateDealer={updateDealerFields} onSaved={()=>loadFromDB(activeMO)}/>}
                  {screen==='months'&&isStaff&&<ManageMonths dealers={dealers} users={users} currentUser={currentUser} monthConfig={monthConfig} saveMonthConfig={saveMonthConfig} loadFromDB={loadFromDB} onSync={syncSheets} syncing={syncing} lastSync={lastSync}/>}
                  {screen==='followups'&&<FollowupsHub notes={myNotes} dealers={myDealers} users={users} onUpdateNote={updateNote} onDeleteNote={deleteNote} onOpenDealer={setEditingId}/>}
                  {screen==='crm'        && <CRM            dealers={myDealers} users={users} currentUser={currentUser}/>}
                  {screen==='attendance' && <AttendancePage users={users} currentUser={currentUser}/>}
                  {screen==='visits'     && <VisitsPage     dealers={myDealers} users={users} currentUser={currentUser}/>}
                  {screen==='leads'      && <LeadsPage      users={users} currentUser={currentUser}/>}
                  {screen==='leaves'     && <LeavesPage     users={users} currentUser={currentUser}/>}
                  {screen==='reports' && isStaff && <Reports dealers={dealers} users={users} currentUser={currentUser} monthConfig={monthConfig} outstandingData={outstandingData}/>}
                  {screen==='tasks'   && <TasksPage   users={users} currentUser={currentUser}/>}
                  {screen==='tickets' && <TicketsPage users={users} currentUser={currentUser}/>}
                  {screen==='admin'&&isStaff&&<AdminPanel dealers={dealers} users={users} setUsers={setUsers} setShowUM={setShowUM} onSync={syncSheets} syncing={syncing} lastSync={lastSync} syncErrs={syncErrs} onNavigate={navigate} onOpenDealer={setEditingId} monthConfig={monthConfig} saveMonthConfig={saveMonthConfig} currentUser={currentUser} onLoginAs={(token, user, impersonatedBy)=>{
                    saveToken(token);
                    localStorage.setItem('stp_jwt', token);
                    if(impersonatedBy){
                      localStorage.setItem('stp_impersonating', JSON.stringify(impersonatedBy));
                      setImpersonatingFrom(impersonatedBy);
                    } else {
                      localStorage.removeItem('stp_impersonating');
                      setImpersonatingFrom(null);
                    }
                    setCurrentUser(user);
                    setTimeout(()=>window.location.reload(), 200);
                  }}/>}
                </>
              )}
            </div>
          </div>
        </div>

        {editing&&<DealerModal dealer={editing} users={users} currentUser={currentUser} onSave={saveDealer} onDelete={deleteDealer} onClose={()=>setEditingId(null)} notes={notes} onAddNote={addNote} onUpdateNote={updateNote} onDeleteNote={deleteNote} onLog={addLog} outstandingData={outstandingData} outFollowups={outFollowups} onFollowupSaved={()=>api.getFollowups().then(d=>setOutFollowups(d)).catch(()=>{})}/>}
        {showAdd&&<AddDealerModal users={users} currentUser={currentUser} onAdd={addDealer} onClose={()=>setShowAdd(false)}/>}
        {showUM&&<UserManagement
          users={users}
          setUsers={setUsers}
          currentUser={currentUser}
          onUsersChanged={refreshUsersFromServer}
          onClose={()=>setShowUM(false)}
          onLoginAs={(token, user, impersonatedBy)=>{
            // Switch the active session to the target user. Store an
            // impersonation marker so the top banner can offer
            // "Return to <originalName>" without re-login.
            saveToken(token);
            localStorage.setItem('stp_jwt', token);
            if(impersonatedBy){
              localStorage.setItem('stp_impersonating', JSON.stringify(impersonatedBy));
              setImpersonatingFrom(impersonatedBy);
            } else {
              localStorage.removeItem('stp_impersonating');
              setImpersonatingFrom(null);
            }
            setCurrentUser(user);
            setShowUM(false);
            // Reload so all month/dealer data is re-fetched as the new user
            setTimeout(()=>window.location.reload(), 200);
          }}
        />}
        {bulkAction&&<BulkActionModal action={bulkAction} selected={selected} dealers={dealers} users={users} onApply={applyBulk} onClose={()=>setBulkAction(null)}/>}
        {showApiSettings && <ApiUrlSettings onClose={()=>setShowApiSettings(false)}/>}
        {/* Global toasts + confirm dialog — replaces window.alert / confirm */}
        <NotificationCenter/>
      </>
    </MonthContext.Provider>
  );
}